import{_ as p,o as e,c as t,ag as o}from"./chunks/framework.DXGyWiRo.js";const c=JSON.parse('{"title":"货币及计费说明","description":"","frontmatter":{},"headers":[],"relativePath":"docs/about/billing_instructions.md","filePath":"docs/about/billing_instructions.md","lastUpdated":null}'),i={name:"docs/about/billing_instructions.md"};function l(r,a,n,s,h,d){return e(),t("div",null,[...a[0]||(a[0]=[o('<h1 id="货币及计费说明" tabindex="-1">货币及计费说明 <a class="header-anchor" href="#货币及计费说明" aria-label="Permalink to &quot;货币及计费说明&quot;">​</a></h1><p>本站点统一使用美元进行计费， 美元兑人民币汇率为 <code>1:7.3</code> 。</p><h3 id="价格" tabindex="-1">价格 <a class="header-anchor" href="#价格" aria-label="Permalink to &quot;价格&quot;">​</a></h3><p>具体价格请查看<a href="https://maisi-ai.com/prices/" target="_blank" rel="noreferrer">价格页面</a>。</p><p>针对不同的渠道来源，折扣有所不同，具体请查看 <a href="#用户权益">用户权益</a>。</p><p>最终的价格为：模型价格 * 渠道折扣 * 用户折扣 。</p><h3 id="用户权益" tabindex="-1">用户权益 <a class="header-anchor" href="#用户权益" aria-label="Permalink to &quot;用户权益&quot;">​</a></h3><p>用户权益是指用户在使用服务时所享有的权益，包括请求速率、折扣等。</p><p>目前根据累计充值金额自动提升用户权益，详情请查看<a href="https://maisi-ai.com/group/" target="_blank" rel="noreferrer">权益页面</a>。</p><p>如果您对速率有更高的要求或者需要企业级服务，欢迎联系我们的客服。</p><h3 id="模型计费" tabindex="-1">模型计费 <a class="header-anchor" href="#模型计费" aria-label="Permalink to &quot;模型计费&quot;">​</a></h3><p>模型计费分以下几种</p><ul><li>按次计费</li><li>按量计费</li><li>按秒计费</li><li>按百万像素计费</li><li>按图像计费</li><li>缓存/音频/推理等额外计费</li></ul><div class="warning custom-block"><p class="custom-block-title">⚠️ 注意</p><p>本系统按照积分计算，所有金额均为积分换算而来，1 积分=$0.000002，最低消费为 1 积分，下面说明忽略了积分的转换。</p></div><h4 id="按次计费" tabindex="-1">按次计费 <a class="header-anchor" href="#按次计费" aria-label="Permalink to &quot;按次计费&quot;">​</a></h4><p>按次计费是指每请求一次， 计费一次。</p><p>计费公式： 模型输入价格 * 渠道折扣 * 用户折扣 。</p><h4 id="按量计费" tabindex="-1">按量计费 <a class="header-anchor" href="#按量计费" aria-label="Permalink to &quot;按量计费&quot;">​</a></h4><p>按量计费是指根据请求使用的<code>tokens</code>数量计费。</p><p>计费公式：</p><p>费用输入输入价格输出输出价格费用=(输入tokens1000×输入价格)+(输出tokens1000×输出价格)最终扣费费用渠道折扣用户折扣最终扣费=费用×渠道折扣×用户折扣</p><h4 id="按秒计费" tabindex="-1">按秒计费 <a class="header-anchor" href="#按秒计费" aria-label="Permalink to &quot;按秒计费&quot;">​</a></h4><p>按秒计费一般出现在视频生成模型中。 计费公式：</p><p>费用输入价格秒数费用=输入价格×秒数最终扣费费用渠道折扣用户折扣最终扣费=费用×渠道折扣×用户折扣</p><h4 id="按百万像素计费" tabindex="-1">按百万像素计费 <a class="header-anchor" href="#按百万像素计费" aria-label="Permalink to &quot;按百万像素计费&quot;">​</a></h4><p>按百万像素计费一般出现在图像生成模型中。 计费公式：</p><p>费用宽度高度输入价格费用=(宽度×高度1000000)×输入价格最终扣费费用渠道折扣用户折扣最终扣费=费用×渠道折扣×用户折扣</p><h4 id="按图像计费" tabindex="-1">按图像计费 <a class="header-anchor" href="#按图像计费" aria-label="Permalink to &quot;按图像计费&quot;">​</a></h4><p>按图像计费一般出现在图像生成模型中。他是按照生成的图像数量计费。 计费公式：</p><p>费用图像数量输入价格费用=图像数量×输入价格最终扣费费用渠道折扣用户折扣最终扣费=费用×渠道折扣×用户折扣</p><h4 id="其他计费" tabindex="-1">其他计费 <a class="header-anchor" href="#其他计费" aria-label="Permalink to &quot;其他计费&quot;">​</a></h4><h5 id="缓存-音频-推理等额外计费" tabindex="-1">缓存/音频/推理等额外计费 <a class="header-anchor" href="#缓存-音频-推理等额外计费" aria-label="Permalink to &quot;缓存/音频/推理等额外计费&quot;">​</a></h5><p>如果模型支持缓存/音频/推理等， 那么这些请求也可能会被计费。 系统的计费方法为：按照输入/输出价格的倍数计费。 计费公式：</p><p>输入输出输入输出（缓存音频推理倍数）输入/输出tokens=输入/输出tokens+（(缓存/音频/推理tokens)×(倍数−1)）</p><p>例如：</p><ul><li>输入 tokens 10000, 输出 tokens 20000, 缓存令牌 1000, 推理令牌 2000</li><li>缓存令牌倍率为 0.5， 推理令牌倍率为 1.5</li></ul><p>那么实际输入 tokens 为：</p><p>实际输入实际输入tokens=10000+(1000×(0.5−1))=10000−500=9500</p><p>那么实际输出 tokens 为：</p><p>实际输出实际输出tokens=20000+(2000×(1.5−1))=20000+1000=21000</p><p>最后按照实际输入/输出 tokens 进行计费，计费方式见<a href="#模型计费">模型计费</a>。</p><p>目前我们有以下计费项目及对应关系：</p><p>计费项目</p><p>对应关系</p><p>说明</p><p>缓存令牌</p><p>输入 tokens * 倍率</p><p>触发自动缓存时，会有该值</p><p>输入音频令牌</p><p>输入 tokens * 倍率</p><p>如有，输入音频时会有该值</p><p>输出音频令牌</p><p>输出 tokens * 倍率</p><p>如有，输出音频时会有该值</p><p>输入图像令牌</p><p>输入 tokens * 倍率</p><p>如有，输入图像时会有该值</p><p>输出图像令牌</p><p>输出 tokens * 倍率</p><p>如有，输出图像时会有该值</p><p>缓存写入5M令牌</p><p>输入 tokens * 倍率</p><p>一般存在于Claude 模型</p><p>缓存写入1H令牌</p><p>输入 tokens * 倍率</p><p>一般存在于Claude 模型</p><p>缓存读取令牌</p><p>输入 tokens * 倍率</p><p>如有，触发缓存时，会有该值</p><p>推理令牌</p><p>输出 tokens * 倍率</p><p>gemini 部分模型计费</p><h5 id="阶梯计费" tabindex="-1">阶梯计费 <a class="header-anchor" href="#阶梯计费" aria-label="Permalink to &quot;阶梯计费&quot;">​</a></h5><p>根据输入tokens的值处于某个阶梯区间内，则按照该阶梯的价格进行计费。 一般存在与Gmini Pro /豆包 系列模型中。</p><p>例如doubao-seed-1-6-lite-251015：</p><ul><li>输入tokens &lt;= 32k时，输入价格是$0.0361645/M，输出是$0.289315/M</li><li>输入tokens &gt; 32k &amp;&amp; 输入tokens &lt;= 128k时，输入价格是$0.0723288/M，输出是$0.482192/M</li><li>输入tokens &gt; 128k时，输入价格是$0.144658/M，输出是$1.44658/M</li></ul><p>计算公式和按量计费公式是一样的，只是根据输入tokens替换了输入/输出的价格</p><h5 id="字段倍率" tabindex="-1">字段倍率 <a class="header-anchor" href="#字段倍率" aria-label="Permalink to &quot;字段倍率&quot;">​</a></h5><p>有些模型会根据请求字段的值来调整价格，一般存在于视频模型中。</p><p>例如kling-v1_videos：</p><p>duration字段允许的值为 5/10秒，默认5秒，当选择 10秒时倍率为2。 mode字段允许的值为 std/pro，默认std，当选择pro时倍率为3.5。</p><p>如果用户请求了 duration=10, mode=pro，那么最终的价格倍率为 2 * 3.5 = 7。</p><p>最终费用计算公式为：</p><p>费用基础费用字段倍率费用=基础费用×字段倍率</p><p>再按照<a href="#模型计费">模型计费</a>中的类型进行最终扣费计算。</p><h3 id="举例" tabindex="-1">举例 <a class="header-anchor" href="#举例" aria-label="Permalink to &quot;举例&quot;">​</a></h3><p>假设：</p><ul><li>您累计充值 1000 美元， 达到权益等级 Tier 3，权益折扣为 0.9。</li><li>OpenAI 官方渠道折扣为 0.88。</li><li>gpt-4o 是按量计费，输入价格为 0.0025 美元/k tokens， 输出价格为 0.01 美元/k tokens。</li><li>gpt-4o 的缓存令牌倍率为 0.5。</li></ul><p>那么您的最终折扣为： 0.9 * 0.88 = 0.792。</p><p>您请求一次 gpt-4o， 输入 1000 tokens， 输出 1000 tokens， 缓存令牌 500 tokens。</p><p>首先我们会计算您实际的输入/输出 tokens：</p><ul><li>实际输入 tokens = 1000 + (500 * (0.5 - 1)) = 1000 - 250 = 750</li><li>实际输出 tokens = 1000</li></ul><p>计费：</p><p>费用费用=(7501000×0.0025)+(10001000×0.01)=0.001875+0.01=0.011875</p><p>最终扣费：</p><p>0.011875×0.792=$0.009405</p>',96)])])}const u=p(i,[["render",l]]);export{c as __pageData,u as default};
